import subprocess
import psutil
import time
import os

def task_func(script_path: str, timeout=10) -> dict:
    # Check if the script path exists
    if not os.path.exists(script_path):
        raise FileNotFoundError(f"Script not found: {script_path}")

    # Ensure the script is executable
    if not os.access(script_path, os.X_OK):
        raise PermissionError(f"Script is not executable: {script_path}")

    # Start the subprocess
    try:
        process = subprocess.Popen([script_path], stdout=subprocess.PIPE, stderr=subprocess.PIPE)
        parent = psutil.Process(process.pid)
    except Exception as e:
        raise RuntimeError(f"Failed to start the script: {e}")

    cpu_usage = 0.0
    memory_usage = 0.0
    start_time = time.time()

    try:
        while True:
            # Check if process is still running
            if not parent.is_running():
                break

            # Check for zombie process
            if parent.status() == psutil.STATUS_ZOMBIE:
                break

            # Get current CPU and memory usage
            try:
                cpu_percent = parent.cpu_percent(interval=0.1)
                memory_info = parent.memory_info()
                rss_bytes = memory_info.rss
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                break

            # Accumulate CPU usage (in percentage)
            cpu_usage += cpu_percent

            # Accumulate memory usage (RSS in bytes)
            memory_usage += rss_bytes

            # Check timeout
            if time.time() - start_time > timeout:
                break

            time.sleep(0.1)

    except Exception as e:
        print(f"Error monitoring process: {e}")

    # Ensure the process is terminated if it's still running
    try:
        if parent.is_running():
            parent.terminate()
            try:
                parent.wait(timeout=3)
            except psutil.TimeoutExpired:
                parent.kill()
    except Exception as e:
        print(f"Failed to terminate process: {e}")

    # Final memory usage
    memory_usage = int(memory_usage)

    return {
        'CPU Usage': cpu_usage,
        'Memory Usage': memory_usage
    }

