import xml.etree.ElementTree as ET
import csv

def task_func(xml_content, output_csv_path):
    try:
        # Parse the input XML content using xml.etree.ElementTree
        root = ET.fromstring(xml_content)
    except ET.ParseError as e:
        # Raise ET.ParseError with the detailed error message if parsing fails
        raise ET.ParseError(f"Failed to parse XML content: {str(e)}")

    # Collect all data rows
    data_rows = []

    # Helper function to recursively extract data from XML elements
    def extract_data(element, parent_tag=None):
        row = {}

        # Add element attributes to the row
        for attr_name, attr_value in element.attrib.items():
            row[f"{element.tag}_{attr_name}"] = attr_value

        # Add text content if it exists
        if element.text and element.text.strip():
            row[f"{element.tag}_text"] = element.text.strip()

        # Recursively process child elements
        for child in element:
            # Handle nested elements by flattening with parent-child naming
            child_tag = child.tag
            if parent_tag:
                child_tag = f"{parent_tag}_{child_tag}"

            # If the child has no children, just add its data
            if len(child) == 0:
                for attr_name, attr_value in child.attrib.items():
                    row[f"{child_tag}_{attr_name}"] = attr_value
                if child.text and child.text.strip():
                    row[f"{child_tag}_text"] = child.text.strip()
            else:
                # If the child has children, process recursively
                extract_data(child, child_tag)

        # If this is a leaf element (no children), add the row
        if len(element) == 0:
            data_rows.append(row)
        else:
            # Otherwise, process children and collect their data
            for child in element:
                extract_data(child, element.tag)

    # Start extraction from the root
    extract_data(root)

    # If no data was collected, still write an empty CSV
    if not data_rows:
        data_rows.append({})

    # Get all unique headers from all rows
    all_headers = set()
    for row in data_rows:
        all_headers.update(row.keys())
    headers = sorted(all_headers)

    # Write to CSV file
    try:
        with open(output_csv_path, 'w', newline='', encoding='utf-8') as csvfile:
            writer = csv.DictWriter(csvfile, fieldnames=headers)
            writer.writeheader()
            writer.writerows(data_rows)
    except IOError as e:
        raise IOError(f"Failed to write to CSV file at {output_csv_path}: {str(e)}")
