            # If input is already a tuple or list of (latitude, longitude)
            return location[0], location[1]
        elif isinstance(location, str):
            # If input is a string address, use geolocator to get coordinates
            try:
                location_data = geolocator.geocode(location)
                if location_data:
                    return location_data.latitude, location_data.longitude
                else:
                    raise ValueError(f"Could not resolve coordinates for address: {location}")
            except Exception as e:
                raise ValueError(f"Geocoding failed for address '{location}': {e}")
        else:
            raise ValueError(f"Unsupported location format: {location}")

    # Process the input dictionary to extract location entries and resolve coordinates
    locations = []
    for key, value in dic.items():
        try:
            lat, lon = resolve_coordinates(value)
            locations.append((lat, lon, key))
        except Exception as e:
            print(f"Skipping invalid location {key}: {e}")

    if not locations:
        raise ValueError("No valid locations provided to map.")

    # Center map on the average of all valid locations
    avg_lat = sum(loc[0] for loc in locations) / len(locations)
    avg_lon = sum(loc[1] for loc in locations) / len(locations)

    # Create the Folium map centered on the average coordinates with an appropriate zoom level
    m = folium.Map(location=[avg_lat, avg_lon], zoom_start=13)

    # Add markers for each location
    for lat, lon, name in locations:
        folium.Marker(
            location=[lat, lon],
            popup=name,
            tooltip=name
        ).add_to(m)

