def lists_to_nested_dict(*lists):
    """
    Convert one or more lists into a nested dictionary, with full edge case handling.

    Supported input types:
    1. Two lists: keys and values → flat dict (key → value)
    2. Three or more lists: hierarchical grouping (level1 → level2 → values)
    3. List of tuples: path-based structure
    4. Multiple lists with matching indices: index-wise grouping into paths

    Handles edge cases:
    - Empty lists
    - Unequal list lengths
    - Non-string or non-hashable keys
    - Invalid input types (e.g., None, malformed nested structures)

    Args:
        *lists: Variable number of lists (or one list of tuples)

    Returns:
        dict: Nested dictionary as per input structure.

    Raises:
        ValueError: If input structure is invalid or lengths don't match.
        TypeError: If inputs are not list-like or contain non-hashable keys.
    """
    # Handle empty arguments
    if not lists:
        return {}

    # Case 1: Single argument that is a list of tuples or lists (path-based)
    if len(lists) == 1:
        input_data = lists[0]
        if input_data is None:
            return {}
        if not isinstance(input_data, (list, tuple)):
            raise TypeError("Single argument must be a list or tuple of paths.")
        if len(input_data) == 0:
            return {}

        # Validate all items are iterable (tuples/lists)
        for item in input_data:
            if not isinstance(item, (list, tuple)):
                raise TypeError(f"All items in path list must be tuples or lists, got {type(item)}")
            if len(item) == 0:
                raise ValueError("Path cannot be empty.")

        result = {}
        for path in input_data:
            current = result
            for i, key in enumerate(path):
                # Check key is hashable
                try:
                    hash(key)
                except TypeError as e:
                    raise TypeError(f"Key '{key}' (type {type(key).__name__}) is not hashable and cannot be used in a dictionary.") from e

                if i == len(path) - 1:
                    # Last item → assign value
                    current[key] = path[-1]
                else:
                    if key not in current:
                        current[key] = {}
                    current = current[key]
        return result

    # Case 2: Multiple lists — validate each is a list/tuple
    for i, lst in enumerate(lists):
        if lst is None:
            raise TypeError(f"List at index {i} is None")
        if not isinstance(lst, (list, tuple)):
            raise TypeError(f"Expected list or tuple at index {i}, got {type(lst).__name__}")

    # Case 2a: Two lists → key-value mapping (flat dictionary)
    if len(lists) == 2:
        keys, values = lists
        if len(keys) == 0 and len(values) == 0:
            return {}
        if len(keys) == 0:
            return {}
        if len(values) == 0:
            raise ValueError("Values list is empty but keys are not.")

        if len(keys) != len(values):
            raise ValueError(f"Length mismatch: keys ({len(keys)}) and values ({len(values)}) must have same length.")

        result = {}
        for i, key in enumerate(keys):
            try:
                hash(key)
            except TypeError as e:
                raise TypeError(f"Key at index {i} ('{key}') is not hashable and cannot be used in a dictionary.") from e

            result[key] = values[i]
        return result

    # Case 2b: Three or more lists → hierarchical grouping
    main_keys = lists[0]
    sub_keys = lists[1]
    values_lists = lists[2:]  # May be multiple value lists

    # Handle empty main_keys
    if len(main_keys) == 0:
        return {}

    # Validate sub_keys
    if len(sub_keys) == 0:
        raise ValueError("Sub-keys list is empty but main keys are not.")

    # Check divisibility of sub_keys length by main_keys length
    if len(sub_keys) % len(main_keys) != 0:
        raise ValueError(
            f"Length of sub_keys ({len(sub_keys)}) must be divisible by length of main_keys ({len(main_keys)}). "
            f"Got remainder {len(sub_keys) % len(main_keys)}."
        )

    n = len(sub_keys) // len(main_keys)

    # Combine all value lists into a single flat list
    flat_values = []
    total_values = 0
    for i, val_list in enumerate(values_lists):
        if isinstance(val_list, (list, tuple)):
            flat_values.extend(val_list)
            total_values += len(val_list)
        else:
            raise TypeError(f"Expected list or tuple for value list {i}, got {type(val_list).__name__}")

    # Validate total values match expected count
    expected_total = len(main_keys) * n
    if total_values != expected_total:
        raise ValueError(
            f"Total values count ({total_values}) does not match expected ({expected_total}). "
            f"Expected {expected_total} values from {len(values_lists)} value lists."
        )

    result = {}
    for i, key in enumerate(main_keys):
        # Validate main key is hashable
        try:
            hash(key)
        except TypeError as e:
            raise TypeError(f"Main key at index {i} ('{key}') is not hashable.") from e

        sub_dict = {}
        start_idx = i * n
        end_idx = start_idx + n

        for j in range(n):
            sub_key = sub_keys[start_idx + j]
            sub_value = flat_values[start_idx + j]

            # Validate sub_key is hashable
            try:
                hash(sub_key)
            except TypeError as e:
                raise TypeError(f"Sub-key at index {start_idx + j} ('{sub_key}') is not hashable.") from e

            sub_dict[sub_key] = sub_value

        result[key] = sub_dict

    return result
