        # Use the function's name or id as a unique identifier for deduplication
        pred_id = getattr(pred, '__name__', id(pred))
        if pred_id not in seen:
            valid_predicates.append(pred)
            seen.add(pred_id)

    if not valid_predicates:
        raise ValueError("No valid predicates provided.")

    # Iterate over each item (file or directory) in the given directory
    # Evaluate only the item's name (not full path) against each deduplicated predicate
    result = {}

    try:
        for item in path.iterdir():
            item_name = item.name
            item_results = {}

            for pred in valid_predicates:
                try:
                    item_results[pred] = pred(item_name)
                except Exception:
                    # If a predicate raises an exception, consider it as False
                    item_results[pred] = False

            result[item_name] = item_results
    except Exception as e:
