import pandas as pd

def task_func(file_name):
    # Read the CSV file
    try:
        df = pd.read_csv(file_name)
    except pd.errors.EmptyDataError:
        # Empty CSV file
        return {}

    # If the DataFrame is empty (no rows), return empty dictionary
    if df.empty:
        return {}

    result = {}

    # Iterate through each column
    for column in df.columns:
        # Count the frequency of each value in the column, ignoring NaN values
        value_counts = df[column].dropna().value_counts()

        # If there are no non-NaN values, we can't determine a most common value
        if value_counts.empty:
            result[column] = None
            continue

        # Get the maximum count
        max_count = value_counts.iloc[0]

        # Get all values that have the maximum count
        most_frequent_values = value_counts[value_counts == max_count].index.tolist()

        # Sort alphabetically and take the first one
        most_frequent_values.sort()
        result[column] = most_frequent_values[0]

    return result
