import collections
import json
import os
def task_func(directory_path: str) -> dict:
    # Initialize an empty dictionary to store the count of each key found across all JSON files
    key_count = collections.defaultdict(int)

    # Iterate through all files in the directory
    for filename in os.listdir(directory_path):
        file_path = os.path.join(directory_path, filename)

        # Check if the file is a JSON file
        if os.path.isfile(file_path) and filename.lower().endswith('.json'):
            try:
                # Open and read the JSON file
                with open(file_path, 'r', encoding='utf-8') as file:
                    data = json.load(file)

                    # Recursively traverse the JSON data to count keys
                    def count_keys(obj):
                        if isinstance(obj, dict):
                            for key in obj.keys():
                                key_count[key] += 1
                                count_keys(obj[key])
                        elif isinstance(obj, list):
                            for item in obj:
                                count_keys(item)

                    count_keys(data)
            except (json.JSONDecodeError, IOError) as e:
                # Skip files that are not valid JSON or can't be read
                continue

    # Convert defaultdict to regular dict before returning
    return dict(key_count)
